class Solution:
    def mergeTriplets(self, triplets, target):
        # Independent: simulate merging all usable triplets into one and compare.
        x, y, z = target
        cur = [0, 0, 0]
        for a, b, c in triplets:
            if a <= x and b <= y and c <= z:
                cur[0] = max(cur[0], a)
                cur[1] = max(cur[1], b)
                cur[2] = max(cur[2], c)
        return cur == target

