class Solution:
    def mergeTriplets(self, triplets, target):
        x, y, z = target
        good = set()
        for a, b, c in triplets:
            if a <= x and b <= y and c <= z:
                if a == x:
                    good.add(0)
                if b == y:
                    good.add(1)
                if c == z:
                    good.add(2)
        return len(good) == 3

