var mergeTriplets = function(triplets, target) {
    const [x, y, z] = target;
    const good = new Set();
    for (const [a, b, c] of triplets) {
        if (a <= x && b <= y && c <= z) {
            if (a === x) good.add(0);
            if (b === y) good.add(1);
            if (c === z) good.add(2);
        }
    }
    return good.size === 3;
};
